holo_ready: () => {
  getPersonalization()
    .then((data) => {
      if (aborted || isRestartingRef.current) return;
      dispatchRef.current({ type: "serverSnapshot", data });
      dispatchRef.current({
        type: "stageComplete",
        stage: "holo_ready",
      });
    })
    .catch(() => {
      // swallow — WS reconnect or poll will retry
    })
    .finally(() => {
      // holo_ready is the terminal stage (fires after `complete` in the
      // backend `_post_complete` task). Close the WS here so we don't
      // miss it — `complete` no longer closes the socket.
      closeWs();
