complete: (p) => {
  // Backend pipeline emits `complete` BEFORE `holo_ready` (holo card
  // runs in a post-complete background task). Don't close the WS here
  // or the holo_ready event is dropped and `has_personalization` never
  // flips true on the client — leaving the giftbox invisible.
  // `has_personalization` is true for `personalization_complete` per
  // the backend phase mapping, so patch it locally too in case the
  // holo_ready follow-up fetch never lands (network drop, etc.).
  dispatchRef.current({
    type: "serverPatch",
    patch: {
      first_message_conversation_id: p.conversation_id ?? undefined,
      phase: "personalization_complete",
      has_personalization: true,
    },
  });
},

